/**통합 게시판 리스트*/ SELECT A.* FROM (
SELECT A.* ,(SELECT COUNT(*) FROM t_board_comment WHERE B_IDX=A.IDX) COMMENT_CNT ,(SELECT user_nm from t_user_info where user_id = A.reg_id) REG_NM2 FROM t_board A WHERE 1=1 and notice_yn = 'N'
ORDER BY REG_DTIME DESC
) A LIMIT #{firstRecordIndex} ,#{recordCountPerPage}

/** 통합게시판 토탈카운트 */
SELECT COUNT(*) FROM t_board 
WHERE 1=1 and notice_yn = 'N'

/** 통합게시판 상세 조회 */
SELECT a.*
,(SELECT user_nm from t_user_info where user_id = a.reg_id) REG_NM2
FROM t_board a
WHERE IDX=#{idx}

mapper.update:
/** 통합게시판 수정 */
UPDATE t_board
SET
TITLE=#{title}
,CONTENT=#{content}
,STATUS=#{status}
,CATE=#{cate}
,MOD_DTIME=#{modDtime}
,FILE_TYPE_GB=#{fileTypeGb}
,NOTICE_YN=#{noticeYn}
WHERE
IDX=#{idx}

/** 통합게시판 답글관련 정보 수정 */
UPDATE t_board
SET
G_IDX=#{gIdx},
G_ORD=#{gOrd},
G_LVL=#{gLvl}
WHERE
IDX=#{idx}

mapper.delete:
/** 통합게시판 게시물 삭제 */
DELETE FROM t_board WHERE
IDX=#{idx}

mapper.update:
/** 통합게시판 조회수 수정 */
UPDATE t_board
SET
HIT=(HIT+1)
WHERE
IDX=#{idx}

/** 통합게시판 상태값 수정 */
UPDATE t_board
SET
STATUS=#{status}
WHERE
IDX=#{idx}

/** 통합게시판 썸네일 수정 */
UPDATE t_board
SET
THUMB_FILE=#{thumbFile}
WHERE
IDX=#{idx}

mapper.select:
/** 이전,이후글 조회 */
SELECT *
FROM t_board
WHERE 1=1
AND BOARD_TYPE = #{boardType}
AND STATUS = 1
AND G_LVL = 0

AND IDX < #{idx}
ORDER BY IDX DESC


AND IDX > #{idx}
ORDER BY IDX ASC

LIMIT 1
